const original = $('Atualizar prompt com contexto').item.json;
const content = $json.choices?.[0]?.message?.content || '{}';

let ia;
try {
  ia = JSON.parse(content);
} catch (error) {
  ia = {
    prioridade: original.prioridade_sugerida_sistema || 'MEDIA',
    categoria: original.tipo_email_sistema || 'OUTRO',
    cliente_ou_projeto: original.cliente_identificado || 'NÃO IDENTIFICADO',
    resumo: content || 'Não foi possível gerar resumo.',
    pendencias: [],
    risco_ou_alerta: 'A IA não retornou JSON válido.',
    resposta_sugerida: '',
    precisa_responder: true,
    prazo_sugerido: original.prazo_sugerido_sistema || 'Hoje'
  };
}

if (!ia.cliente_ou_projeto || ia.cliente_ou_projeto === 'NÃO IDENTIFICADO') {
  ia.cliente_ou_projeto = original.cliente_identificado || 'NÃO IDENTIFICADO';
}

if (!ia.categoria || ia.categoria === 'OUTRO') {
  ia.categoria = original.tipo_email_sistema || ia.categoria || 'OUTRO';
}

if (!ia.prioridade) {
  ia.prioridade = original.prioridade_sugerida_sistema || 'MEDIA';
}

const pendenciasTexto = Array.isArray(ia.pendencias) && ia.pendencias.length
  ? ia.pendencias.map(p => `• ${p}`).join('\n')
  : '• Nenhuma pendência clara identificada.';

const corPrioridade = ia.prioridade === 'ALTA' ? '🔴' : ia.prioridade === 'MEDIA' ? '🟡' : '🟢';

const mensagemTeams = `🤖 **Secretária IA - Novo e-mail**

${corPrioridade} **Prioridade:** ${ia.prioridade || 'MEDIA'}
📂 **Categoria:** ${ia.categoria || original.tipo_email_sistema || 'OUTRO'}
🏢 **Cliente:** ${original.cliente_identificado || 'NÃO IDENTIFICADO'}
🌐 **Domínio:** ${original.dominio_cliente || 'nao-identificado'}
📦 **Projeto:** ${original.projeto_detectado_sistema || 'NÃO IDENTIFICADO'}
⏰ **Prazo sugerido:** ${ia.prazo_sugerido || original.prazo_sugerido_sistema || 'Hoje'}
🧠 **Motivo:** ${original.motivo_prioridade_sistema || 'Análise automática.'}

📧 **De:** ${original.from}
📌 **Assunto:** ${original.subject}

📝 **Resumo:**
${ia.resumo || 'Sem resumo.'}

✅ **Pendências:**
${pendenciasTexto}

⚠️ **Alerta:**
${ia.risco_ou_alerta || 'Nenhum alerta importante.'}

✍️ **Resposta sugerida:**
${ia.resposta_sugerida || 'Nenhuma resposta sugerida.'}

_Obs.: nada foi enviado ao cliente. Apenas análise para aprovação._`;

return [{
  json: {
    ...original,
    ...ia,
    mensagemTeams,
    TEAMS_WEBHOOK_URL: original.TEAMS_WEBHOOK_URL
  }
}];

const fromRaw = String($json.from || '');
const match = fromRaw.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
const destinatario = match ? match[0] : fromRaw;

const assuntoResposta = String($json.subject || '').toLowerCase().startsWith('re:')
  ? $json.subject
  : `Re: ${$json.subject || '(sem assunto)'}`;

const corpoResposta = $json.resposta_sugerida || 'Olá, tudo bem? Recebi sua mensagem e vou verificar.';

const approveUrl = `${$execution.resumeUrl}?acao=aprovar`;

const mensagem = $json.mensagemTeams || '';
const textoCard = `${mensagem}

━━━━━━━━━━━━━━━━━━━━
✅ Para enviar a resposta sugerida ao cliente, clique no botão abaixo.
📧 Destinatário: ${destinatario}
📌 Assunto: ${assuntoResposta}`;

return [
  {
    json: {
      ...$json,
      destinatario_resposta: destinatario,
      assunto_resposta: assuntoResposta,
      corpo_resposta: corpoResposta,
      approve_url: approveUrl,
      adaptiveCard: {
        attachments: [
          {
            contentType: "application/vnd.microsoft.card.adaptive",
            content: {
              type: "AdaptiveCard",
              version: "1.4",
              body: [
                {
                  type: "TextBlock",
                  text: textoCard,
                  wrap: true
                }
              ],
              actions: [
                {
                  type: "Action.OpenUrl",
                  title: "✅ OK, enviar resposta",
                  url: approveUrl
                }
              ]
            }
          }
        ]
      }
    }
  }
];

const item = $json;

function pick(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== '') return String(value);
  }
  return '';
}

const fromRaw = pick(item.from, item.fromAddress, item.headers?.from, '');
const emailMatch = fromRaw.match(/[A-Z0-9._%+-]+@([A-Z0-9.-]+\.[A-Z]{2,})/i);

let dominio = emailMatch ? emailMatch[1].toLowerCase() : 'nao-identificado';

dominio = dominio
  .replace(/[>,;)]/g, '')
  .trim();

const sufixos = [
  '.com.br',
  '.org.br',
  '.edu.br',
  '.gov.br',
  '.net.br',
  '.adv.br',
  '.cont.br',
  '.com',
  '.org',
  '.net',
  '.edu',
  '.gov',
  '.br'
];

let cliente = dominio;

for (const sufixo of sufixos) {
  if (cliente.endsWith(sufixo)) {
    cliente = cliente.slice(0, -sufixo.length);
    break;
  }
}

// Se tiver subdomínio, pega o nome principal antes do sufixo.
// Ex: suporte.lbv.org.br -> lbv
const partes = cliente.split('.').filter(Boolean);
if (partes.length > 1) {
  cliente = partes[partes.length - 1];
}

cliente = cliente
  .replace(/[-_]+/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .toUpperCase();

if (!cliente || cliente === 'NAO IDENTIFICADO') {
  cliente = 'NÃO IDENTIFICADO';
}

const projeto = cliente === 'LBV' ? 'SimpleDFe / Integração RM' : 'NÃO IDENTIFICADO';
const prioridadePadrao = cliente === 'LBV' ? 'ALTA' : 'MEDIA';
const sla = cliente === 'LBV' ? 'Hoje' : 'A definir';

return [{
  json: {
    ...item,
    dominio_cliente: dominio,
    cliente_identificado: cliente,
    projeto_identificado: projeto,
    prioridade_padrao_cliente: prioridadePadrao,
    sla_cliente: sla
  }
}];

const item = $json;

const prompt = `
Você é a Secretária IA do Matheus, consultor de sistemas, TOTVS RM, SimpleIT e SimpleDFE.

IMPORTANTE:
Os dados abaixo foram identificados automaticamente antes da IA.
Use estes dados como fonte principal e só altere se o conteúdo do e-mail justificar claramente.

CONTEXTO IDENTIFICADO:
Cliente: ${item.cliente_identificado}
Domínio: ${item.dominio_cliente}
Tipo sugerido: ${item.tipo_email_sistema}
Projeto sugerido: ${item.projeto_detectado_sistema}
Prioridade sugerida: ${item.prioridade_sugerida_sistema}
Motivo da prioridade: ${item.motivo_prioridade_sistema}
Prazo sugerido: ${item.prazo_sugerido_sistema}

Analise o e-mail abaixo e responda SOMENTE em JSON válido, sem markdown, com esta estrutura:

{
  "prioridade": "ALTA | MEDIA | BAIXA",
  "categoria": "SUPORTE | COMERCIAL | FINANCEIRO | REUNIAO | CONTRATO | PESSOAL | OUTRO",
  "cliente_ou_projeto": "use o cliente identificado e projeto quando existirem",
  "resumo": "resumo curto e objetivo",
  "pendencias": ["pendência 1", "pendência 2"],
  "risco_ou_alerta": "algo importante ou vazio",
  "resposta_sugerida": "resposta educada, profissional e curta, pronta para o Matheus revisar antes de enviar",
  "precisa_responder": true,
  "prazo_sugerido": "Hoje | Amanhã | Esta semana | Sem urgência"
}

Regras:
- Não invente informação.
- Se cliente_identificado estiver preenchido, use esse cliente.
- Use a categoria sugerida, salvo se o conteúdo indicar outra com clareza.
- Use a prioridade sugerida, salvo se o e-mail for claramente menos ou mais urgente.
- Se for cobrança, erro de sistema, cliente irritado, proposta ou reunião, destaque em risco_ou_alerta.
- A resposta sugerida deve ser em português do Brasil.
- Nunca envie resposta diretamente ao cliente; apenas prepare para aprovação.

E-MAIL:
De: ${item.from}
Para: ${item.to}
Data: ${item.date}
Assunto: ${item.subject}

Conteúdo:
${item.text}
`;

return [{
  json: {
    ...item,
    prompt
  }
}];

const item = $json;

const assunto = String(item.subject || '').toLowerCase();
const corpo = String(item.text || '').toLowerCase();
const texto = `${assunto} ${corpo}`;

function contem(lista) {
  return lista.some(palavra => texto.includes(palavra));
}

let tipo_email = 'OUTRO';
let projeto_detectado = item.projeto_identificado || 'NÃO IDENTIFICADO';
let prioridade_sugerida = item.prioridade_padrao_cliente || 'MEDIA';
let motivo_prioridade = 'Prioridade padrão.';

// SUPORTE / ERRO
if (contem([
  'erro', 'falha', 'problema', 'não funciona', 'nao funciona', 'parou',
  'integração', 'integracao', 'rm', 'totvs', 'xml', 'nfe', 'nf-e',
  'nfse', 'nfs-e', 'cte', 'ct-e', 'tss', 'rejeição', 'rejeicao',
  'urgente', 'produção', 'producao'
])) {
  tipo_email = 'SUPORTE';
  prioridade_sugerida = 'ALTA';
  motivo_prioridade = 'Palavras de erro/suporte/urgência detectadas.';
}

// COMERCIAL
if (contem([
  'proposta', 'orçamento', 'orcamento', 'valor', 'preço', 'preco',
  'contratar', 'contratação', 'contratacao', 'demonstração', 'demonstracao',
  'apresentação', 'apresentacao', 'licença', 'licenca', 'mensalidade'
])) {
  tipo_email = 'COMERCIAL';
  if (prioridade_sugerida !== 'ALTA') prioridade_sugerida = 'MEDIA';
  motivo_prioridade = 'Possível oportunidade comercial.';
}

// FINANCEIRO
if (contem([
  'boleto', 'pagamento', 'nota fiscal', 'nf ', 'fatura', 'cobrança',
  'cobranca', 'vencimento', 'pix', 'recibo', 'em aberto', 'inadimplente'
])) {
  tipo_email = 'FINANCEIRO';
  if (contem(['vencido', 'em aberto', 'inadimplente', 'urgente'])) {
    prioridade_sugerida = 'ALTA';
    motivo_prioridade = 'Financeiro com possível cobrança/urgência.';
  } else if (prioridade_sugerida !== 'ALTA') {
    prioridade_sugerida = 'MEDIA';
    motivo_prioridade = 'Assunto financeiro.';
  }
}

// REUNIÃO
if (contem([
  'reunião', 'reuniao', 'call', 'agenda', 'agendar', 'meet',
  'teams', 'horário', 'horario', 'disponibilidade', 'alinhamento'
])) {
  tipo_email = 'REUNIAO';
  if (prioridade_sugerida !== 'ALTA') prioridade_sugerida = 'MEDIA';
  motivo_prioridade = 'Pedido ou assunto de reunião.';
}

// CONTRATO
if (contem([
  'contrato', 'aditivo', 'assinatura', 'termo', 'proposta assinada',
  'documento para assinatura'
])) {
  tipo_email = 'CONTRATO';
  if (prioridade_sugerida !== 'ALTA') prioridade_sugerida = 'MEDIA';
  motivo_prioridade = 'Assunto contratual.';
}

// PROJETO
if (contem(['simpledfe', 'simple dfe', 'dfe', 'nf-e', 'nfe', 'nfs-e', 'nfse', 'ct-e', 'cte', 'xml'])) {
  projeto_detectado = 'SimpleDFe';
}

if (contem(['nucleus', 'portal rm', 'educacional', 'portal educacional'])) {
  projeto_detectado = 'Nucleus / TOTVS RM Educacional';
}

if (contem(['erp', 'financeiro', 'contas a pagar', 'contas a receber', 'borderô', 'bordero'])) {
  projeto_detectado = 'SimpleERP / Financeiro';
}

if (contem(['totvs rm', 'rm ', 'fórmula visual', 'formula visual', 'metadados', 'relatório', 'relatorio'])) {
  projeto_detectado = projeto_detectado === 'NÃO IDENTIFICADO'
    ? 'TOTVS RM'
    : projeto_detectado;
}

const prazo_sugerido_sistema = prioridade_sugerida === 'ALTA'
  ? 'Hoje'
  : prioridade_sugerida === 'MEDIA'
    ? 'Esta semana'
    : 'Sem urgência';

return [{
  json: {
    ...item,
    tipo_email_sistema: tipo_email,
    projeto_detectado_sistema: projeto_detectado,
    prioridade_sugerida_sistema: prioridade_sugerida,
    motivo_prioridade_sistema: motivo_prioridade,
    prazo_sugerido_sistema
  }
}];

const item = $json;

const fromRaw = String(item.from || '');
const match = fromRaw.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
const destinatario = item.destinatario_resposta || (match ? match[0] : fromRaw);

const assunto = item.assunto_resposta || (
  String(item.subject || '').toLowerCase().startsWith('re:')
    ? item.subject
    : `Re: ${item.subject || '(sem assunto)'}`
);

const corpo = item.corpo_resposta || item.resposta_sugerida || '';

return [{
  json: {
    ...item,
    destinatario_resposta: destinatario,
    assunto_resposta: assunto,
    corpo_resposta: corpo
  }
}];

const texto = `✅ **Resposta enviada ao cliente**

📧 Para: ${$json.destinatario_resposta}
📌 Assunto: ${$json.assunto_resposta}

A resposta sugerida foi enviada após sua aprovação.`;

return [{
  json: {
    adaptiveCard: {
      attachments: [
        {
          contentType: "application/vnd.microsoft.card.adaptive",
          content: {
            type: "AdaptiveCard",
            version: "1.4",
            body: [
              {
                type: "TextBlock",
                text: texto,
                wrap: true
              }
            ]
          }
        }
      ]
    }
  }
}];
